   372→int anetUnixGenericConnect(char *err, char *path, int flags)
   373→{
   374→    int s;
   375→    struct sockaddr_un sa;
   376→
   377→    if ((s = anetCreateSocket(err,AF_LOCAL)) == ANET_ERR)
   378→        return ANET_ERR;
   379→
   380→    sa.sun_family = AF_LOCAL;
   381→    strncpy(sa.sun_path,path,sizeof(sa.sun_path)-1);
   382→    if (flags & ANET_CONNECT_NONBLOCK) {
   383→        if (anetNonBlock(err,s) != ANET_OK) {
   384→            close(s);
   385→            return ANET_ERR;
   386→        }
   387→    }
   388→    if (connect(s,(struct sockaddr*)&sa,sizeof(sa)) == -1) {
   389→        if (errno == EINPROGRESS &&
   390→            flags & ANET_CONNECT_NONBLOCK)
   391→            return s;
   392→
   393→        anetSetError(err, "connect: %s", strerror(errno));
   394→        close(s);
   395→        return ANET_ERR;
   396→    }
   397→    return s;
   398→}
   399→
   400→int anetUnixConnect(char *err, char *path)
   401→{
   402→    return anetUnixGenericConnect(err,path,ANET_CONNECT_NONE);
   403→}
   404→
   405→int anetUnixNonBlockConnect(char *err, char *path)
   406→{
   407→    return anetUnixGenericConnect(err,path,ANET_CONNECT_NONBLOCK);
   408→}
   409→
   410→/* Like read(2) but make sure 'count' is read before to return
   411→ * (unless error or EOF condition is encountered) */
   412→int anetRead(int fd, char *buf, int count)
   413→{
   414→    ssize_t nread, totlen = 0;
   415→    while(totlen != count) {
   416→        nread = read(fd,buf,count-totlen);
   417→        if (nread == 0) return totlen;
   418→        if (nread == -1) return -1;
   419→        totlen += nread;
   420→        buf += nread;
   421→    }
   422→    return totlen;
   423→}
   424→
   425→/* Like write(2) but make sure 'count' is written before to return
   426→ * (unless error is encountered) */
   427→int anetWrite(int fd, char *buf, int count)
   428→{
   429→    ssize_t nwritten, totlen = 0;
   430→    while(totlen != count) {
   431→        nwritten = write(fd,buf,count-totlen);
   432→        if (nwritten == 0) return totlen;
   433→        if (nwritten == -1) return -1;
   434→        totlen += nwritten;
   435→        buf += nwritten;
   436→    }
   437→    return totlen;
   438→}
