   440→static int anetListen(char *err, int s, struct sockaddr *sa, socklen_t len, int backlog) {
   441→    if (bind(s,sa,len) == -1) {
   442→        anetSetError(err, "bind: %s", strerror(errno));
   443→        close(s);
   444→        return ANET_ERR;
   445→    }
   446→
   447→    if (listen(s, backlog) == -1) {
   448→        anetSetError(err, "listen: %s", strerror(errno));
   449→        close(s);
   450→        return ANET_ERR;
   451→    }
   452→    return ANET_OK;
   453→}
   454→
   455→static int anetV6Only(char *err, int s) {
   456→    int yes = 1;
   457→    if (setsockopt(s,IPPROTO_IPV6,IPV6_V6ONLY,&yes,sizeof(yes)) == -1) {
   458→        anetSetError(err, "setsockopt: %s", strerror(errno));
   459→        close(s);
   460→        return ANET_ERR;
   461→    }
   462→    return ANET_OK;
   463→}
   464→
   465→static int _anetTcpServer(char *err, int port, char *bindaddr, int af, int backlog)
   466→{
   467→    int s = -1, rv;
   468→    char _port[6];  /* strlen("65535") */
   469→    struct addrinfo hints, *servinfo, *p;
   470→
   471→    snprintf(_port,6,"%d",port);
   472→    memset(&hints,0,sizeof(hints));
   473→    hints.ai_family = af;
   474→    hints.ai_socktype = SOCK_STREAM;
   475→    hints.ai_flags = AI_PASSIVE;    /* No effect if bindaddr != NULL */
   476→
   477→    if ((rv = getaddrinfo(bindaddr,_port,&hints,&servinfo)) != 0) {
   478→        anetSetError(err, "%s", gai_strerror(rv));
   479→        return ANET_ERR;
   480→    }
   481→    for (p = servinfo; p != NULL; p = p->ai_next) {
   482→        if ((s = socket(p->ai_family,p->ai_socktype,p->ai_protocol)) == -1)
   483→            continue;
   484→
   485→        if (af == AF_INET6 && anetV6Only(err,s) == ANET_ERR) goto error;
   486→        if (anetSetReuseAddr(err,s) == ANET_ERR) goto error;
   487→        if (anetListen(err,s,p->ai_addr,p->ai_addrlen,backlog) == ANET_ERR) s = ANET_ERR;
   488→        goto end;
   489→    }
   490→    if (p == NULL) {
   491→        anetSetError(err, "unable to bind socket, errno: %d", errno);
   492→        goto error;
   493→    }
   494→
   495→error:
   496→    if (s != -1) close(s);
   497→    s = ANET_ERR;
   498→end:
   499→    freeaddrinfo(servinfo);
   500→    return s;
   501→}
   502→
   503→int anetTcpServer(char *err, int port, char *bindaddr, int backlog)
   504→{
   505→    return _anetTcpServer(err, port, bindaddr, AF_INET, backlog);
   506→}
   507→
   508→int anetTcp6Server(char *err, int port, char *bindaddr, int backlog)
   509→{
   510→    return _anetTcpServer(err, port, bindaddr, AF_INET6, backlog);
   511→}
   512→
   513→int anetUnixServer(char *err, char *path, mode_t perm, int backlog)
   514→{
   515→    int s;
   516→    struct sockaddr_un sa;
   517→
   518→    if ((s = anetCreateSocket(err,AF_LOCAL)) == ANET_ERR)
   519→        return ANET_ERR;
   520→
   521→    memset(&sa,0,sizeof(sa));
   522→    sa.sun_family = AF_LOCAL;
   523→    strncpy(sa.sun_path,path,sizeof(sa.sun_path)-1);
   524→    if (anetListen(err,s,(struct sockaddr*)&sa,sizeof(sa),backlog) == ANET_ERR)
   525→        return ANET_ERR;
   526→    if (perm)
   527→        chmod(sa.sun_path, perm);
   528→    return s;
   529→}
