   531→static int anetGenericAccept(char *err, int s, struct sockaddr *sa, socklen_t *len) {
   532→    int fd;
   533→    while(1) {
   534→        fd = accept(s,sa,len);
   535→        if (fd == -1) {
   536→            if (errno == EINTR)
   537→                continue;
   538→            else {
   539→                anetSetError(err, "accept: %s", strerror(errno));
   540→                return ANET_ERR;
   541→            }
   542→        }
   543→        break;
   544→    }
   545→    return fd;
   546→}
   547→
   548→int anetTcpAccept(char *err, int s, char *ip, size_t ip_len, int *port) {
   549→    int fd;
   550→    struct sockaddr_storage sa;
   551→    socklen_t salen = sizeof(sa);
   552→    if ((fd = anetGenericAccept(err,s,(struct sockaddr*)&sa,&salen)) == -1)
   553→        return ANET_ERR;
   554→
   555→    if (sa.ss_family == AF_INET) {
   556→        struct sockaddr_in *s = (struct sockaddr_in *)&sa;
   557→        if (ip) inet_ntop(AF_INET,(void*)&(s->sin_addr),ip,ip_len);
   558→        if (port) *port = ntohs(s->sin_port);
   559→    } else {
   560→        struct sockaddr_in6 *s = (struct sockaddr_in6 *)&sa;
   561→        if (ip) inet_ntop(AF_INET6,(void*)&(s->sin6_addr),ip,ip_len);
   562→        if (port) *port = ntohs(s->sin6_port);
   563→    }
   564→    return fd;
   565→}
   566→
   567→int anetUnixAccept(char *err, int s) {
   568→    int fd;
   569→    struct sockaddr_un sa;
   570→    socklen_t salen = sizeof(sa);
   571→    if ((fd = anetGenericAccept(err,s,(struct sockaddr*)&sa,&salen)) == -1)
   572→        return ANET_ERR;
   573→
   574→    return fd;
   575→}
