   577→int anetPeerToString(int fd, char *ip, size_t ip_len, int *port) {
   578→    struct sockaddr_storage sa;
   579→    socklen_t salen = sizeof(sa);
   580→
   581→    if (getpeername(fd,(struct sockaddr*)&sa,&salen) == -1) goto error;
   582→    if (ip_len == 0) goto error;
   583→
   584→    if (sa.ss_family == AF_INET) {
   585→        struct sockaddr_in *s = (struct sockaddr_in *)&sa;
   586→        if (ip) inet_ntop(AF_INET,(void*)&(s->sin_addr),ip,ip_len);
   587→        if (port) *port = ntohs(s->sin_port);
   588→    } else if (sa.ss_family == AF_INET6) {
   589→        struct sockaddr_in6 *s = (struct sockaddr_in6 *)&sa;
   590→        if (ip) inet_ntop(AF_INET6,(void*)&(s->sin6_addr),ip,ip_len);
   591→        if (port) *port = ntohs(s->sin6_port);
   592→    } else if (sa.ss_family == AF_UNIX) {
   593→        if (ip) strncpy(ip,"/unixsocket",ip_len);
   594→        if (port) *port = 0;
   595→    } else {
   596→        goto error;
   597→    }
   598→    return 0;
   599→
   600→error:
   601→    if (ip) {
   602→        if (ip_len >= 2) {
   603→            ip[0] = '?';
   604→            ip[1] = '\0';
   605→        } else if (ip_len == 1) {
   606→            ip[0] = '\0';
   607→        }
   608→    }
   609→    if (port) *port = 0;
   610→    return -1;
   611→}
   612→
   613→/* Format an IP,port pair into something easy to parse. If IP is IPv6
   614→ * (matches for ":"), the ip is surrounded by []. IP and port are just
   615→ * separated by colons. This the standard to display addresses within Redis. */
   616→int anetFormatAddr(char *buf, size_t buf_len, char *ip, int port) {
   617→    return snprintf(buf,buf_len, strchr(ip,':') ?
   618→           "[%s]:%d" : "%s:%d", ip, port);
   619→}
   620→
   621→/* Like anetFormatAddr() but extract ip and port from the socket's peer. */
   622→int anetFormatPeer(int fd, char *buf, size_t buf_len) {
   623→    char ip[INET6_ADDRSTRLEN];
   624→    int port;
   625→
   626→    anetPeerToString(fd,ip,sizeof(ip),&port);
   627→    return anetFormatAddr(buf, buf_len, ip, port);
   628→}
