   630→int anetSockName(int fd, char *ip, size_t ip_len, int *port) {
   631→    struct sockaddr_storage sa;
   632→    socklen_t salen = sizeof(sa);
   633→
   634→    if (getsockname(fd,(struct sockaddr*)&sa,&salen) == -1) {
   635→        if (port) *port = 0;
   636→        ip[0] = '?';
   637→        ip[1] = '\0';
   638→        return -1;
   639→    }
   640→    if (sa.ss_family == AF_INET) {
   641→        struct sockaddr_in *s = (struct sockaddr_in *)&sa;
   642→        if (ip) inet_ntop(AF_INET,(void*)&(s->sin_addr),ip,ip_len);
   643→        if (port) *port = ntohs(s->sin_port);
   644→    } else {
   645→        struct sockaddr_in6 *s = (struct sockaddr_in6 *)&sa;
   646→        if (ip) inet_ntop(AF_INET6,(void*)&(s->sin6_addr),ip,ip_len);
   647→        if (port) *port = ntohs(s->sin6_port);
   648→    }
   649→    return 0;
   650→}
   651→
   652→int anetFormatSock(int fd, char *fmt, size_t fmt_len) {
   653→    char ip[INET6_ADDRSTRLEN];
